import "./Transition.css";

import { motion } from "framer-motion";

const Transition = (Page) => {
  return function WithTransition(props) {
    return (
      <>
        <Page {...props} />

        <motion.div
          className="slide-in"
          initial={{ scaleY: 0 }}
          animate={{ scaleY: 0 }}
          exit={{ scaleY: 1 }}
