.preloader-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100svh;
  z-index: 9999;
  pointer-events: none;
  overflow: hidden;
}

.preloader-grid {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  overflow: hidden;
}

.preloader-grid .preloader-block {
  position: absolute;
  background-color: var(--base-400);
  opacity: 1;
  box-sizing: border-box;
  will-change: opacity;
}

.preloader-animation-wrapper {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1;
}

.preloader-text {
  position: absolute;
  bottom: 6rem;
  color: var(--base-100);
  animation: preloader-blink 1s ease-in-out infinite;
  animation-delay: 100ms;
  z-index: 2;
  opacity: 0;
}

@keyframes preloader-blink {
  0%,
  100% {
    opacity: 0.1;
  }
  50% {
    opacity: 1;
  }
}

.preloader-ring-frame,
.preloader-disc-frame {
  height: 100%;
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  position: absolute;
}

